import sys

def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    H = int(data[0])
    W = int(data[1])
    grid = [list(map(int, list(row))) for row in data[2:]]

    # Precompute column sums
    col_ones = [sum(grid[i][j] for i in range(H)) for j in range(W)]

    # Precompute cost for flipping each column
    col_cost = [W - col_ones[j] for j in range(W)]

    min_total = float('inf')

    # Try all possible combinations of flipping columns (W <= 18)
    for mask in range(1 << W):
        total = 0
        for j in range(W):
            if (mask >> j) & 1:
                total += col_cost[j]

        # Calculate effective row values after column flips
        row_sum = [0] * H
        for i in range(H):
            cnt = 0
            for j in range(W):
                if (mask >> j) & 1:
                    cnt += 1 - grid[i][j]
                else:
                    cnt += grid[i][j]
            row_sum[i] = cnt

        # Optimal row flips: flip rows with more 1s after column flips
        row_flips = 0
        for i in range(H):
            if row_sum[i] > H - row_sum[i]:
                row_flips += 1

        # Final sum calculation
        final_sum = 0
        for i in range(H):
            for j in range(W):
                val = grid[i][j]
                if (mask >> j) & 1:
                    val = 1 - val
                if row_flips % 2 == 1:
                    val = 1 - val
                final_sum += val

        min_total = min(min_total, final_sum)

    print(min_total)

if __name__ == "__main__":
    main()
